const raw = $input.first().json;
const b = raw.body || raw;
return [{ json: {
  name: b.name || 'Customer',
  email: b.email || '',
  phone: b.phone || '',
  vehicle_interest: b.vehicle_interest || 'our premium vehicles',
  budget: b.budget_max ? `AED ${b.budget_min || 0} - ${b.budget_max}` : 'flexible',
  lead_id: b.lead_id || b.id || null,
  source: b.source || 'website',
  enrolled_at: new Date().toISOString()
}}];

const leadData = $input.first().json;
const lead = Array.isArray(leadData) ? leadData[0] : leadData;
const originalLead = $node['Prepare Lead Data'].json;

// Exit drip if lead has converted
const exitStatuses = ['won', 'qualified', 'negotiation'];
if (lead && exitStatuses.includes(lead.status)) {
  return [{ json: { ...originalLead, drip_exit: true, exit_reason: `Lead converted to ${lead.status}` } }];
}
if (lead && lead.ai_priority === 'HOT') {
  return [{ json: { ...originalLead, drip_exit: true, exit_reason: 'Lead upgraded to HOT' } }];
}

return [{ json: { ...originalLead, drip_exit: false } }];

