const ai = $input.first().json;
const lead = $node['Conversion Gate'].json;
let emailHtml;
try { emailHtml = ai.choices[0].message.content.trim(); } catch(e) {
  emailHtml = `<h2>Hi ${lead.name},</h2><p>Thank you for your interest in NEXUS OS! We have an incredible selection of premium vehicles waiting for you.</p><p>Reply to this email or call us to schedule your personal showroom tour.</p><br><p>Best regards,<br>NEXUS OS Sales Team</p>`;
}
return [{ json: { ...lead, emailHtml, stage: 'day1_welcome' } }];

